import '../styles/appointment.css';
import axios from 'axios';
import { useState } from 'react';
import doctorImg from '../purveyors_images/JoybackgroundIMG.png';// 👈 change name if needed

function Appointment() {
  const [formData, setFormData] = useState({
    department: '',
    doctor: '',
    name: '',
    phone: '',
    date: ''
  });

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      await axios.post('http://localhost:5000/api/appointment', formData);
      alert("Appointment booked!");
    } catch (error) {
      console.error(error);
      alert("Error booking appointment");
    }
  };

  return (
    <div className="appointment-container">

      {/* LEFT SIDE IMAGE */}
      <div className="appointment-left">
        <img src="../purveyors_images/joybackgroundIMG.png" alt="Doctor" />
      </div>

      {/* RIGHT SIDE FORM */}
      <div className="appointment-right">
        <h2>Book Appointment</h2>

        <form onSubmit={handleSubmit}>
          
          <select name="department" onChange={handleChange} required>
            <option value="">Select Department</option>
            <option>Cardiology</option>
            <option>Dermatology</option>
            <option>Neurology</option>
          </select>

          <select name="doctor" onChange={handleChange} required>
            <option value="">Select Doctor</option>
            <option>Dr. Smith</option>
            <option>Dr. John</option>
          </select>

          <input 
            type="text"
            name="name"
            placeholder="Full Name"
            onChange={handleChange}
            required
          />

          <input 
            type="text"
            name="phone"
            placeholder="Phone Number"
            onChange={handleChange}
            required
          />

          <input 
            type="date"
            name="date"
            onChange={handleChange}
            required
          />

          <button type="submit">BOOK YOUR APPOINTMENT</button>
        </form>
      </div>

    </div>
  );
}

export default Appointment;
